using System;
using System.Collections.Concurrent;
using System.IO;
using System.Threading;
using System.Windows.Forms;

namespace WeldMonitor3
{
    public static class Logger
    {
        private static TextBox _targetTextBox;

        // 비동기 파일 로깅용
        private static ConcurrentQueue<string> _logQueue = new ConcurrentQueue<string>();
        private static Thread _fileLogThread;
        private static bool _isRunning = false;
        private static string _logBaseFolder;
        private static readonly object _fileLock = new object();
        private const int MAX_QUEUE_SIZE = 10000;  // 큐 최대 크기 제한 (메모리 보호)

        public static void Initialize(TextBox targetTextBox)
        {
            _targetTextBox = targetTextBox;

            // 로그 폴더 설정 (프로그램 실행 경로\Log)
            _logBaseFolder = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "Log");

            // 파일 로깅 스레드 시작
            StartFileLogging();
        }

        /// <summary>
        /// 파일 로깅 스레드 시작
        /// </summary>
        private static void StartFileLogging()
        {
            if (_isRunning) return;

            _isRunning = true;
            _fileLogThread = new Thread(FileLogWorker)
            {
                IsBackground = true,
                Name = "FileLogThread"
            };
            _fileLogThread.Start();
        }

        /// <summary>
        /// 파일 로깅 스레드 종료
        /// </summary>
        public static void Shutdown()
        {
            _isRunning = false;

            // 남은 로그 모두 기록
            FlushLogs();

            if (_fileLogThread != null && _fileLogThread.IsAlive)
            {
                _fileLogThread.Join(1000); // 최대 1초 대기
            }
        }

        /// <summary>
        /// 파일 로깅 워커 스레드
        /// </summary>
        private static void FileLogWorker()
        {
            while (_isRunning)
            {
                try
                {
                    // 큐에서 로그 메시지 꺼내서 파일에 기록
                    while (_logQueue.TryDequeue(out string logMessage))
                    {
                        WriteToFile(logMessage);
                    }

                    // CPU 부하 방지 (50ms 대기)
                    Thread.Sleep(50);
                }
                catch
                {
                    // 로깅 스레드 오류 무시 (검사에 영향 X)
                }
            }

            // 종료 시 남은 로그 처리
            FlushLogs();
        }

        /// <summary>
        /// 남은 로그 모두 파일에 기록
        /// </summary>
        private static void FlushLogs()
        {
            while (_logQueue.TryDequeue(out string logMessage))
            {
                WriteToFile(logMessage);
            }
        }

        /// <summary>
        /// 파일에 로그 기록 (년\월\일 폴더 구조)
        /// </summary>
        private static void WriteToFile(string message)
        {
            try
            {
                DateTime now = DateTime.Now;

                // 폴더 경로: Log\2026\01\10
                string folderPath = Path.Combine(
                    _logBaseFolder,
                    now.Year.ToString(),
                    now.Month.ToString("D2"),
                    now.Day.ToString("D2")
                );

                // 폴더 생성
                if (!Directory.Exists(folderPath))
                {
                    Directory.CreateDirectory(folderPath);
                }

                // 파일 경로: Log\2026\01\10\log_20260110.txt
                string fileName = $"log_{now:yyyyMMdd}.txt";
                string filePath = Path.Combine(folderPath, fileName);

                // 파일에 추가 기록
                lock (_fileLock)
                {
                    File.AppendAllText(filePath, message + Environment.NewLine);
                }
            }
            catch
            {
                // 파일 기록 실패 시 무시 (검사에 영향 X)
            }
        }

        /// <summary>
        /// 로그 출력 (TextBox + 파일)
        /// </summary>
        public static void Log(string message)
        {
            string time = DateTime.Now.ToString("HH:mm:ss.fff");
            string formattedMessage = $"[{time}] {message}";

            // 파일 로깅 큐에 추가 (비동기) - 최대 크기 초과 시 오래된 항목 제거
            if (_logQueue.Count >= MAX_QUEUE_SIZE)
            {
                _logQueue.TryDequeue(out _);  // 오래된 로그 1개 버림
            }
            _logQueue.Enqueue(formattedMessage);

            // TextBox 출력
            if (_targetTextBox == null) return;

            if (_targetTextBox.InvokeRequired)
            {
                _targetTextBox.BeginInvoke(new Action(() => AppendMessage(message)));
            }
            else
            {
                AppendMessage(message);
            }
        }

        public static void Error(string message)
        {
            Log("[ERROR] " + message);
        }

        public static void Clear()
        {
            if (_targetTextBox == null) return;

            if (_targetTextBox.InvokeRequired)
            {
                _targetTextBox.BeginInvoke(new Action(() => _targetTextBox.Clear()));
            }
            else
            {
                _targetTextBox.Clear();
            }
        }

        private static void AppendMessage(string message)
        {
            string time = DateTime.Now.ToString("HH:mm:ss");
            _targetTextBox.AppendText($"[{time}] {message}{Environment.NewLine}");
            _targetTextBox.SelectionStart = _targetTextBox.Text.Length;
            _targetTextBox.ScrollToCaret();
        }
    }
}

