using System;
using System.Drawing;
using System.Windows.Forms;

namespace WeldMonitor3
{
    /// <summary>
    /// 다크테마 색상 관리 및 적용 클래스
    /// </summary>
    public static class ThemeManager
    {
        // 다크테마 색상 정의
        public static class DarkTheme
        {
            public static readonly Color BackgroundDark = ColorTranslator.FromHtml("#1e1e1e");      // 어두운 배경
            public static readonly Color BackgroundMedium = ColorTranslator.FromHtml("#2b2b2b");   // 중간 배경
            public static readonly Color BackgroundLight = ColorTranslator.FromHtml("#3c3c3c");    // 밝은 배경
            public static readonly Color TextPrimary = ColorTranslator.FromHtml("#ffffff");        // 주 텍스트
            public static readonly Color TextSecondary = ColorTranslator.FromHtml("#cccccc");      // 보조 텍스트
            public static readonly Color Accent = ColorTranslator.FromHtml("#007acc");             // 강조 색상
            public static readonly Color BorderColor = ColorTranslator.FromHtml("#555555");        // 테두리
            public static readonly Color SuccessColor = ColorTranslator.FromHtml("#4ec9b0");       // 성공 (OK)
            public static readonly Color ErrorColor = ColorTranslator.FromHtml("#f48771");         // 오류 (NG)
        }

        /// <summary>
        /// 폼과 모든 하위 컨트롤에 다크테마 적용
        /// </summary>
        public static void ApplyDarkTheme(Form form)
        {
            if (form == null) return;

            // 폼 배경색
            form.BackColor = DarkTheme.BackgroundMedium;
            form.ForeColor = DarkTheme.TextPrimary;

            // 모든 하위 컨트롤에 재귀 적용
            ApplyThemeToControls(form.Controls);
        }

        /// <summary>
        /// 컨트롤 컬렉션에 재귀적으로 테마 적용
        /// </summary>
        private static void ApplyThemeToControls(Control.ControlCollection controls)
        {
            foreach (Control control in controls)
            {
                ApplyThemeToControl(control);

                // 하위 컨트롤이 있으면 재귀 호출
                if (control.HasChildren)
                {
                    ApplyThemeToControls(control.Controls);
                }
            }
        }

        /// <summary>
        /// 개별 컨트롤에 테마 적용
        /// </summary>
        private static void ApplyThemeToControl(Control control)
        {
            // Panel, GroupBox
            if (control is Panel || control is GroupBox)
            {
                control.BackColor = DarkTheme.BackgroundDark;
                control.ForeColor = DarkTheme.TextPrimary;
            }
            // Button
            else if (control is Button button)
            {
                button.BackColor = DarkTheme.BackgroundLight;
                button.ForeColor = DarkTheme.TextPrimary;
                button.FlatStyle = FlatStyle.Flat;
                button.FlatAppearance.BorderColor = DarkTheme.BorderColor;
                button.FlatAppearance.BorderSize = 1;
            }
            // TextBox
            else if (control is TextBox textBox)
            {
                textBox.BackColor = DarkTheme.BackgroundLight;
                textBox.ForeColor = DarkTheme.TextPrimary;
                textBox.BorderStyle = BorderStyle.FixedSingle;
            }
            // Label
            else if (control is Label label)
            {
                // 배경이 투명이 아닌 경우만 변경
                if (label.BackColor != Color.Transparent)
                {
                    label.BackColor = DarkTheme.BackgroundMedium;
                }
                label.ForeColor = DarkTheme.TextPrimary;
            }
            // DataGridView
            else if (control is DataGridView grid)
            {
                grid.BackgroundColor = DarkTheme.BackgroundMedium;
                grid.GridColor = DarkTheme.BorderColor;
                grid.DefaultCellStyle.BackColor = DarkTheme.BackgroundMedium;
                grid.DefaultCellStyle.ForeColor = DarkTheme.TextPrimary;
                grid.DefaultCellStyle.SelectionBackColor = DarkTheme.Accent;
                grid.DefaultCellStyle.SelectionForeColor = DarkTheme.TextPrimary;
                grid.ColumnHeadersDefaultCellStyle.BackColor = DarkTheme.BackgroundLight;
                grid.ColumnHeadersDefaultCellStyle.ForeColor = DarkTheme.TextPrimary;
                grid.RowHeadersDefaultCellStyle.BackColor = DarkTheme.BackgroundLight;
                grid.RowHeadersDefaultCellStyle.ForeColor = DarkTheme.TextPrimary;
                grid.EnableHeadersVisualStyles = false;
            }
            // ComboBox
            else if (control is ComboBox comboBox)
            {
                comboBox.BackColor = DarkTheme.BackgroundLight;
                comboBox.ForeColor = DarkTheme.TextPrimary;
                comboBox.FlatStyle = FlatStyle.Flat;
            }
            // CheckBox, RadioButton
            else if (control is CheckBox || control is RadioButton)
            {
                control.BackColor = Color.Transparent;
                control.ForeColor = DarkTheme.TextPrimary;
            }
            // NumericUpDown
            else if (control is NumericUpDown numeric)
            {
                numeric.BackColor = DarkTheme.BackgroundLight;
                numeric.ForeColor = DarkTheme.TextPrimary;
            }
            // TabControl
            else if (control is TabControl tabControl)
            {
                tabControl.BackColor = DarkTheme.BackgroundMedium;
                foreach (TabPage page in tabControl.TabPages)
                {
                    page.BackColor = DarkTheme.BackgroundMedium;
                    page.ForeColor = DarkTheme.TextPrimary;
                }
            }
            // ListView
            else if (control is ListView listView)
            {
                listView.BackColor = DarkTheme.BackgroundMedium;
                listView.ForeColor = DarkTheme.TextPrimary;
            }
            // TreeView
            else if (control is TreeView treeView)
            {
                treeView.BackColor = DarkTheme.BackgroundMedium;
                treeView.ForeColor = DarkTheme.TextPrimary;
            }
            // TableLayoutPanel
            else if (control is TableLayoutPanel)
            {
                control.BackColor = DarkTheme.BackgroundDark;
                control.ForeColor = DarkTheme.TextPrimary;
            }
            // PropertyGrid
            else if (control is PropertyGrid propertyGrid)
            {
                propertyGrid.BackColor = DarkTheme.BackgroundMedium;
                propertyGrid.ViewBackColor = DarkTheme.BackgroundLight;
                propertyGrid.ViewForeColor = DarkTheme.TextPrimary;
                propertyGrid.CategoryForeColor = DarkTheme.TextPrimary;
                propertyGrid.HelpBackColor = DarkTheme.BackgroundDark;
                propertyGrid.HelpForeColor = DarkTheme.TextPrimary;
                propertyGrid.LineColor = DarkTheme.BorderColor;
            }
            // PictureBox
            else if (control is PictureBox pictureBox)
            {
                // 배경은 다크테마, 이미지는 원본 유지
                pictureBox.BackColor = DarkTheme.BackgroundMedium;
            }
            // ScottPlot (그래프)는 별도 처리 필요 - 여기서는 배경만
            else if (control.GetType().Name.Contains("FormsPlot"))
            {
                control.BackColor = DarkTheme.BackgroundDark;
            }
            // 기타 컨트롤
            else
            {
                control.BackColor = DarkTheme.BackgroundMedium;
                control.ForeColor = DarkTheme.TextPrimary;
            }
        }

        /// <summary>
        /// ScottPlot 그래프에 다크테마 적용 (별도 호출 필요)
        /// </summary>
        public static void ApplyDarkThemeToPlot(ScottPlot.WinForms.FormsPlot plot)
        {
            if (plot?.Plot == null) return;

            var plot2 = plot.Plot;

            // 배경색
            plot2.FigureBackground.Color = ScottPlot.Color.FromHex("#1e1e1e");
            plot2.DataBackground.Color = ScottPlot.Color.FromHex("#2b2b2b");

            // 그리드
            plot2.Grid.MajorLineColor = ScottPlot.Color.FromHex("#555555");

            // 축
            plot2.Axes.Color(ScottPlot.Color.FromHex("#ffffff"));

            plot.Refresh();
        }
    }
}

