 56→        private List<string> FindAllCsvFiles(DateTime startDate, DateTime endDate)
 57→        {
 58→            string baseDir = GlobalValues.GetDataPath();
 59→            List<string> resultFiles = new List<string>();
 60→
 61→            for (DateTime date = startDate; date <= endDate; date = date.AddDays(1))
 62→            {
 63→                string folder = Path.Combine(baseDir, date.ToString("yyyy"), date.ToString("MM"), date.ToString("dd"));
 64→                if (!Directory.Exists(folder)) continue;
 65→
 66→                string[] files = Directory.GetFiles(folder, "*.csv");
 67→                resultFiles.AddRange(files);
 68→            }
 69→
 70→            return resultFiles;
 71→        }
