        private void ThreadTask1()
        {
            // Arduino SW 버전에 따라 프로토콜 분기
            if (GlobalValues.aduinoSwVer == "2.0")
            {
                ThreadTask1_V2();  // 바이너리 프로토콜 (신규)
            }
            else
            {
                ThreadTask1_V1();  // 텍스트 프로토콜 (기존)
            }
        }

        // v1.0 텍스트 프로토콜 (기존 방식)
        private void ThreadTask1_V1()
        {
            // 시작 시 버퍼 클리어
            if (SerialAduino.BytesToRead > 0)
                SerialAduino.DiscardInBuffer();

            while (SerialAduino.IsOpen)
            {
                try
                {
                    string incoming = SerialAduino.ReadLine();

                    if (!string.IsNullOrEmpty(incoming))
                    {
                        // 버퍼에 쌓인 데이터 있으면 버리고 최신 데이터만 사용
                        if (SerialAduino.BytesToRead > 0)
                            SerialAduino.DiscardInBuffer();

                        string line = incoming.Trim();
                        // 디버그: 수신 데이터 로깅
                        System.Diagnostics.Debug.WriteLine($"[Arduino V1] Raw: '{line}' (len={line.Length})");

                        if (line.StartsWith("S") && line.EndsWith("E") && line.Length == 34)
                        {
                            // DI 파싱 (16비트)
                            for (int i = 0; i < 16; i++)
                            {
                                IO.IN[i] = (line.Substring(i + 1, 1) == "1");
                            }
                            // 디버그: IO.IN 상태 로깅
                            string ioStatus = string.Join("", IO.IN.Take(8).Select(b => b ? "1" : "0"));
                            System.Diagnostics.Debug.WriteLine($"[Arduino V1] IO.IN[0-7]: {ioStatus}");

                            // UI 업데이트 - 비동기 일괄 처리 (btnIn은 8개)
                            this.BeginInvoke(new MethodInvoker(() =>
                            {
                                for (int i = 0; i < btnIn.Length; i++)
                                {
                                    if (IO.IN[i])
                                    {
                                        btnIn[i].BackColor = pColor.Theme.LightRed;
                                        btnIn[i].ForeColor = System.Drawing.Color.Black;
                                    }
                                    else
                                    {
                                        btnIn[i].BackColor = pColor.Theme.DeepRed;
                                        btnIn[i].ForeColor = System.Drawing.Color.White;
                                    }
                                }
                            }));

                            // 아날로그 파싱 (for문 밖에서 1번만)
                            try
                            {
                                double raw1 = Convert.ToDouble(line.Substring(17, 4));
                                double raw2 = Convert.ToDouble(line.Substring(21, 4));
                                double raw3 = Convert.ToDouble(line.Substring(25, 4));

                                if (GlobalValues.weldMode == "SPOT")
                                {
                                    // SPOT 모드: 전류/온도/공압 (전류 단위: kA)
                                    double ampRaw = (raw1 / 100.0 * 3.0) * Amp.Tol;
                                    double tempRaw = ((raw2 / 100.0 * 25.0) - 25.0) * Volt.Tol;
                                    double airRaw = (((raw3 / 100.0 * 0.25) - 0.25) * 10.204) * Flow.Tol;

                                    Amp.Value = Math.Max(0, Math.Round(AmpFilter.Update(ampRaw), 1));
                                    Volt.Value = Math.Max(0, Math.Round(VoltFilter.Update(tempRaw), 1));
                                    Flow.Value = Math.Max(0, Math.Round(FlowFilter.Update(airRaw), 1));
                                }
                                else
                                {
                                    // CO2 모드: 전류/전압/유량
                                    double ampRaw = (raw1 / 100.0 * 60.0) * Amp.Tol;
                                    double voltRaw = (raw2 / 100.0 * 25.0) * Volt.Tol;
                                    double flowRaw = ((raw3 / 100.0 * 12.5) - 12.5) * Flow.Tol;

                                    Amp.Value = Math.Max(0, Math.Round(AmpFilter.Update(ampRaw), 1));
                                    Volt.Value = Math.Max(0, Math.Round(VoltFilter.Update(voltRaw), 1));
                                    Flow.Value = Math.Max(0, Math.Round(FlowFilter.Update(flowRaw), 1));
                                }

                                // UI 업데이트 - 비동기
                                this.BeginInvoke(new MethodInvoker(() =>
                                {
                                    labelAmp.Text = Amp.Value.ToString("0.00");
                                    labelVolt.Text = Volt.Value.ToString("0.00");
                                    labelFlow.Text = Flow.Value.ToString("0.00");
                                }));
                            }
                            catch (Exception parseEx)
                            {
                                Logger.Log(LanguageManager.Get("log_analog_parse_error", parseEx.Message));
                            }
                        }
                    }
                }
                catch (Exception ex)
                {
                }
                Thread.Sleep(1);
            }
        }

        // v2.0 바이너리 프로토콜 (신규)
        private void ThreadTask1_V2()
        {
            byte[] buffer = new byte[12];  // 패킷 크기: Header(1) + DI(2) + AI(8) + Checksum(1)
            int readIndex = 0;

            while (SerialAduino.IsOpen)
            {
                try
                {
                    int available = SerialAduino.BytesToRead;
                    if (available > 0)
                    {
                        // 헤더 찾기
                        if (readIndex == 0)
                        {
                            byte b = (byte)SerialAduino.ReadByte();
                            if (b == 0x52)  // 헤더 확인
                            {
                                buffer[0] = b;
                                readIndex = 1;
                            }
                        }
                        else
                        {
                            // 나머지 패킷 읽기
                            int bytesToRead = Math.Min(12 - readIndex, available);
                            int bytesRead = SerialAduino.Read(buffer, readIndex, bytesToRead);
                            readIndex += bytesRead;

                            // 패킷 완성되면 파싱
                            if (readIndex >= 12)
                            {
                                // 체크섬 검증
                                byte checksum = 0;
                                for (int i = 1; i < 11; i++)  // Header와 Checksum 제외
                                {
                                    checksum ^= buffer[i];
                                }

                                if (checksum == buffer[11])
                                {
                                    // DI 파싱 (Little Endian, 16비트 전체)
                                    ushort diValue = (ushort)(buffer[1] | (buffer[2] << 8));
                                    for (int i = 0; i < 16; i++)
                                    {
                                        IO.IN[i] = ((diValue >> i) & 1) == 1;
                                    }

                                    // UI 업데이트 - btnIn은 8개만
                                    this.BeginInvoke(new MethodInvoker(() =>
                                    {
                                        for (int i = 0; i < btnIn.Length; i++)
                                        {
                                            if (IO.IN[i])
                                            {
                                                btnIn[i].BackColor = pColor.Theme.LightRed;
                                                btnIn[i].ForeColor = System.Drawing.Color.Black;
                                            }
                                            else
                                            {
                                                btnIn[i].BackColor = pColor.Theme.DeepRed;
                                                btnIn[i].ForeColor = System.Drawing.Color.White;
                                            }
                                        }
                                    }));

                                    // AI 파싱 (Little Endian)
                                    ushort ai0 = (ushort)(buffer[3] | (buffer[4] << 8));
                                    ushort ai1 = (ushort)(buffer[5] | (buffer[6] << 8));
                                    ushort ai2 = (ushort)(buffer[7] | (buffer[8] << 8));
                                    ushort ai3 = (ushort)(buffer[9] | (buffer[10] << 8));

                                    // ADC 값 -> 실제 물리값 변환 (모드별 분기)
                                    if (GlobalValues.weldMode == "SPOT")
                                    {
                                        // SPOT 모드: 전류/온도/공압 (전류 단위: kA)
                                        double ampRaw = (ai0 / 1023.0 * 3.0) * Amp.Tol;
                                        double tempRaw = ((ai1 / 1023.0 * 25.0) - 25.0) * Volt.Tol;
                                        double airRaw = (((ai2 / 1023.0 * 0.25) - 0.25) * 10.204) * Flow.Tol;

                                        Amp.Value = Math.Max(0, Math.Round(AmpFilter.Update(ampRaw), 1));
                                        Volt.Value = Math.Max(0, Math.Round(VoltFilter.Update(tempRaw), 1));
                                        Flow.Value = Math.Max(0, Math.Round(FlowFilter.Update(airRaw), 1));
                                    }
                                    else
                                    {
                                        // CO2 모드: 전류/전압/유량
                                        double ampRaw = (ai0 / 1023.0 * 60.0) * Amp.Tol;
                                        double voltRaw = (ai1 / 1023.0 * 25.0) * Volt.Tol;
                                        double flowRaw = ((ai2 / 1023.0 * 12.5) - 12.5) * Flow.Tol;

                                        Amp.Value = Math.Max(0, Math.Round(AmpFilter.Update(ampRaw), 1));
                                        Volt.Value = Math.Max(0, Math.Round(VoltFilter.Update(voltRaw), 1));
                                        Flow.Value = Math.Max(0, Math.Round(FlowFilter.Update(flowRaw), 1));
                                    }

                                    labelAmp.Invoke(new MethodInvoker(() =>
                                    {
                                        labelAmp.Text = $"{Amp.Value.ToString("0.00")}";
                                        labelVolt.Text = $"{Volt.Value.ToString("0.00")}";
                                        labelFlow.Text = $"{Flow.Value.ToString("0.00")}";
                                    }));
                                }
                                else
                                {
                                    Logger.Log(LanguageManager.Get("log_checksum_error"));
                                }

                                readIndex = 0;  // 다음 패킷 대기
                            }
                        }
                    }
                }
                catch (Exception ex)
                {
                    Logger.Log(LanguageManager.Get("log_v2_protocol_error", ex.Message));
                    readIndex = 0;  // 에러 시 초기화
                }
                Thread.Sleep(1);
            }
        }
        private void WriteGrid(
            DataGridView grid,
            int jigId, int point, int totalPoint, bool passOption,
            double min1, double val1Avr, double max1, double val1Max, double val1Min, string type1,
            double min2, double val2Avr, double max2, double val2Max, double val2Min, string type2,
            double min3, double val3Avr, double max3, double val3Max, double val3Min, string type3,
            double elapsedTime, int wPoint)
        {

            if (grid.InvokeRequired)
            {
                grid.Invoke((MethodInvoker)(() => WriteGrid(
                    grid, jigId, point, totalPoint, passOption,
                    min1, val1Avr, max1, val1Max, val1Min, type1,
                    min2, val2Avr, max2, val2Max, val2Min, type2,
                    min3, val3Avr, max3, val3Max, val3Min, type3,
                    elapsedTime, wPoint)));
                return;
            }

            bool[] decision = new bool[3];
            double[] values = new double[3];

            // SPOT 모드 Volt/Flow 사용 여부
            bool useVolt = GlobalValues.weldMode != "SPOT" || GlobalValues.spotUseVolt;
            bool useFlow = GlobalValues.weldMode != "SPOT" || GlobalValues.spotUseFlow;

            // 1번 항목 판정 (Amp - 항상 사용)
            values[0] = (type1 == "Maximum" || type1 == "Max") ? val1Max : val1Avr;
            decision[0] = (values[0] >= min1 && values[0] <= max1);

            // 2번 항목 판정 (Volt/온도 - SPOT 모드에서 선택적)
            if (useVolt)
            {
                values[1] = (type2 == "Maximum" || type2 == "Max") ? val2Max : val2Avr;
                decision[1] = (values[1] >= min2 && values[1] <= max2);
            }
            else
            {
                values[1] = 0;
                decision[1] = true;  // 미사용 시 항상 OK
            }

            // 3번 항목 판정 (Flow/공압 - SPOT 모드에서 선택적)
            if (useFlow)
            {
                values[2] = (type3 == "Maximum" || type3 == "Max") ? val3Max : val3Avr;
                decision[2] = (values[2] >= min3 && values[2] <= max3);
            }
            else
            {
                values[2] = 0;
                decision[2] = true;  // 미사용 시 항상 OK
            }

            string result = "NG";
            if (passOption || (decision[0] && decision[1] && decision[2]))
            {
                result = (passOption) ? "PASS" : "OK";
            }
            else
            {
                result = "NG";
            }

            // 행 추가 - 미사용 항목은 공란으로 표시
            string val1Str = values[0].ToString("0.00");
            string min1Str = min1.ToString("0.00");
            string max1Str = max1.ToString("0.00");

            string val2Str = useVolt ? values[1].ToString("0.00") : "-";
            string min2Str = useVolt ? min2.ToString("0.00") : "-";
            string max2Str = useVolt ? max2.ToString("0.00") : "-";

            string val3Str = useFlow ? values[2].ToString("0.00") : "-";
            string min3Str = useFlow ? min3.ToString("0.00") : "-";
            string max3Str = useFlow ? max3.ToString("0.00") : "-";

            //InitGrid();
            int rowIndex = grid.Rows.Add(
                jigId.ToString(),
                $"{point}//{totalPoint}",
                min1Str, val1Str, max1Str,
                min2Str, val2Str, max2Str,
                min3Str, val3Str, max3Str,
                elapsedTime.ToString("0.0"),
                result
            );

            // 셀 색상 지정 (다크테마: 밝은 파랑/빨강)
            var okColor = System.Drawing.Color.FromArgb(100, 180, 255);   // 밝은 파랑
            var ngColor = System.Drawing.Color.FromArgb(255, 100, 100);   // 밝은 빨강
            grid.Rows[rowIndex].Cells[3].Style.ForeColor = decision[0] ? okColor : ngColor;
            if (useVolt)
                grid.Rows[rowIndex].Cells[6].Style.ForeColor = decision[1] ? okColor : ngColor;
            if (useFlow)
                grid.Rows[rowIndex].Cells[9].Style.ForeColor = decision[2] ? okColor : ngColor;

            // 최종 판정 색상 (조건부: 사용하는 항목만 판정)
            bool allOk = decision[0] && decision[1] && decision[2];
            grid.Rows[rowIndex].Cells[12].Style.ForeColor = allOk ? okColor : ngColor;

            // 마지막 행 보이게
            grid.FirstDisplayedScrollingRowIndex = grid.Rows.Count - 1;
            if (result == "OK" || result == "PASS")
            {
                data.Point_OK[point - 1] = 1;
            }
            else
            {
                data.Point_OK[point - 1] = 0;
            }
        }
