        /// <summary>
        /// SPOT 모드 Volt/Flow 사용 설정에 따라 그래프/라벨 표시/숨김
        /// </summary>
        public void ApplyGraphLayout()
        {
            // SPOT 모드가 아니면 모든 그래프 표시
            bool showVolt = true;
            bool showFlow = true;

            if (GlobalValues.weldMode == "SPOT")
            {
                showVolt = GlobalValues.spotUseVolt;
                showFlow = GlobalValues.spotUseFlow;
            }

            // Volt(온도) 그래프/라벨 표시
            panel8.Visible = showVolt;
            label2.Visible = showVolt;
            labelVolt.Visible = showVolt;

            // Flow(공압) 그래프/라벨 표시
            panel10.Visible = showFlow;
            label1.Visible = showFlow;
            labelFlow.Visible = showFlow;

            // 그래프 개수에 따른 크기 조정
            int graphCount = 1 + (showVolt ? 1 : 0) + (showFlow ? 1 : 0);

            // 기준 좌표 (이미지 사용 여부에 따라 다름)
            int startX = GlobalValues.useImageFeature ? 329 : 12;
            int graphWidth = GlobalValues.useImageFeature ? 386 : 703;
            int startY = 65;
            int totalHeight = 482;  // panel3 상단부터 panel10 하단까지

            if (graphCount == 3)
            {
                // 3개: 원래 레이아웃
                panel3.Location = new System.Drawing.Point(startX, startY);
                panel3.Size = new System.Drawing.Size(graphWidth, 168);

                panel8.Location = new System.Drawing.Point(startX, startY + 176);
                panel8.Size = new System.Drawing.Size(graphWidth, 149);

                panel10.Location = new System.Drawing.Point(startX, startY + 333);
                panel10.Size = new System.Drawing.Size(graphWidth, 149);
            }
            else if (graphCount == 2)
            {
                // 2개: 높이 균등 분배
                int graphHeight = (totalHeight - 8) / 2;  // 간격 8px

                panel3.Location = new System.Drawing.Point(startX, startY);
                panel3.Size = new System.Drawing.Size(graphWidth, graphHeight);

                if (showVolt)
                {
                    panel8.Location = new System.Drawing.Point(startX, startY + graphHeight + 8);
                    panel8.Size = new System.Drawing.Size(graphWidth, graphHeight);
                }
                else if (showFlow)
                {
                    panel10.Location = new System.Drawing.Point(startX, startY + graphHeight + 8);
                    panel10.Size = new System.Drawing.Size(graphWidth, graphHeight);
                }
            }
            else
            {
                // 1개: Amp만 꽉 차게
                panel3.Location = new System.Drawing.Point(startX, startY);
                panel3.Size = new System.Drawing.Size(graphWidth, totalHeight);
            }

            // 그래프 Refresh
            formsPlot1.Refresh();
            if (showVolt) formsPlot2.Refresh();
            if (showFlow) formsPlot3.Refresh();
        }

