461→        /// <summary>
462→        /// 체크 변경 시 타임스탬프 로그 기록
463→        /// </summary>
464→        private void LogCheckAction(int itemNo, string itemName, int day, string oldVal, string newVal)
465→        {
466→            try
467→            {
468→                string logPath = GetLogFilePath();
469→                string timestamp = DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss");
470→                string oldDisplay = string.IsNullOrEmpty(oldVal) ? "-" : oldVal;
471→                string newDisplay = string.IsNullOrEmpty(newVal) ? "-" : newVal;
472→                string logLine = $"[{timestamp}] 항목 {itemNo} ({itemName}) | {day}일 | {oldDisplay} → {newDisplay}";
473→
474→                File.AppendAllText(logPath, logLine + Environment.NewLine, System.Text.Encoding.UTF8);
475→            }
476→            catch { }
477→        }
478→
479→        #endregion
480→
481→        #region PDF 출력
482→
483→        private void BtnPdf_Click(object sender, EventArgs e)
484→        {
485→            using (var sfd = new SaveFileDialog())
486→            {
487→                sfd.Filter = "PDF 파일|*.pdf";
488→                sfd.FileName = $"점검체크시트_{_currentMonth:yyyy_MM}.pdf";
489→
490→                if (sfd.ShowDialog() != DialogResult.OK) return;
491→
492→                try
493→                {
494→                    using (var pd = new PrintDocument())
495→                    {
496→                        pd.PrintPage += PrintCheckSheet;
497→                        pd.DefaultPageSettings.Landscape = true;
498→                        pd.DefaultPageSettings.Margins = new Margins(30, 30, 30, 30);
499→
500→                        // Microsoft Print to PDF 확인
501→                        bool pdfPrinterFound = false;
502→                        foreach (string printer in PrinterSettings.InstalledPrinters)
503→                        {
504→                            if (printer.Contains("Microsoft Print to PDF"))
505→                            {
506→                                pd.PrinterSettings.PrinterName = printer;
507→                                pdfPrinterFound = true;
508→                                break;
509→                            }
510→                        }
511→
512→                        if (!pdfPrinterFound)
513→                        {
514→                            MessageBox.Show("'Microsoft Print to PDF' 프린터를 찾을 수 없습니다.\n인쇄 대화상자에서 PDF 프린터를 선택해주세요.",
515→                                "알림", MessageBoxButtons.OK, MessageBoxIcon.Warning);
516→
517→                            using (var printDlg = new PrintDialog())
518→                            {
519→                                printDlg.Document = pd;
520→                                if (printDlg.ShowDialog() != DialogResult.OK) return;
521→                            }
522→                            pd.Print();
523→                        }
524→                        else
525→                        {
526→                            pd.PrinterSettings.PrintToFile = true;
527→                            pd.PrinterSettings.PrintFileName = sfd.FileName;
528→                            pd.Print();
529→                        }
530→                    }
531→
532→                    // PDF 생성 후 열기
533→                    if (File.Exists(sfd.FileName))
534→                    {
535→                        System.Diagnostics.Process.Start(sfd.FileName);
536→                        LogCheckAction(0, "PDF 출력", 0, "", sfd.FileName);
537→                    }
538→                }
539→                catch (Exception ex)
540→                {
541→                    MessageBox.Show($"PDF 생성 실패: {ex.Message}", "오류",
542→                        MessageBoxButtons.OK, MessageBoxIcon.Error);
543→                }
544→            }
545→        }
