547→        /// <summary>
548→        /// 체크시트 인쇄 렌더링 (Landscape A4)
549→        /// </summary>
550→        private void PrintCheckSheet(object sender, PrintPageEventArgs e)
551→        {
552→            Graphics g = e.Graphics;
553→            var area = e.MarginBounds;
554→            float x = area.Left;
555→            float y = area.Top;
556→            float pageW = area.Width;
557→
558→            // 폰트
559→            var fontTitle = new Font("맑은 고딕", 14, FontStyle.Bold);
560→            var fontHeader = new Font("맑은 고딕", 7);
561→            var fontHeaderBold = new Font("맑은 고딕", 7, FontStyle.Bold);
562→            var fontCell = new Font("맑은 고딕", 6.5f);
563→            var fontCellBold = new Font("맑은 고딕", 7, FontStyle.Bold);
564→            var fontSmall = new Font("맑은 고딕", 6);
565→
566→            var penBlack = new Pen(Color.Black, 0.5f);
567→            var penBold = new Pen(Color.Black, 1.2f);
568→            var brushBlack = Brushes.Black;
569→            var brushGreen = new SolidBrush(Color.FromArgb(0, 128, 0));
570→            var brushRed = new SolidBrush(Color.FromArgb(200, 0, 0));
571→            var sfCenter = new StringFormat { Alignment = StringAlignment.Center, LineAlignment = StringAlignment.Center };
572→            var sfLeft = new StringFormat { Alignment = StringAlignment.Near, LineAlignment = StringAlignment.Center };
573→
574→            // === 제목 ===
575→            g.DrawString("(설비/용접조건) 점검 체크시트", fontTitle, brushBlack, x + pageW / 2, y, sfCenter);
576→            y += 28;
577→
578→            // === 헤더 정보 ===
579→            string headerLine1 = $"관리부서: {txtDept.Text}    관리감독: {txtSupervisor.Text}    설비명칭: {txtEquipName.Text}    " +
580→                                 $"점검방법: 점검 항목/점검 기준/점검 방법에 따름";
581→            string headerLine2 = $"품질: {txtQuality.Text}    설비번호: {txtEquipNo.Text}    " +
582→                                 $"작성: {txtWriter.Text}    검토: {txtReviewer.Text}    승인: {txtApprover.Text}    " +
583→                                 $"{_currentMonth:yyyy년 MM월} 일상 점검";
584→            g.DrawString(headerLine1, fontHeader, brushBlack, x, y);
585→            y += 14;
586→            g.DrawString(headerLine2, fontHeader, brushBlack, x, y);
587→            y += 18;
588→
589→            // === 테이블 ===
590→            int daysInMonth = DateTime.DaysInMonth(_currentMonth.Year, _currentMonth.Month);
591→            int totalCols = 5 + daysInMonth;
592→
593→            // 컬럼 폭 계산
594→            float[] colWidths = new float[5 + 31];
595→            colWidths[0] = 22;   // NO
596→            colWidths[1] = 130;  // 점검항목
597→            colWidths[2] = 125;  // 점검기준
598→            colWidths[3] = 45;   // 점검방법
599→            colWidths[4] = 48;   // 구분
600→            float fixedW = colWidths[0] + colWidths[1] + colWidths[2] + colWidths[3] + colWidths[4];
601→            float dayColW = (pageW - fixedW) / daysInMonth;
602→            for (int d = 0; d < daysInMonth; d++)
603→                colWidths[5 + d] = dayColW;
604→
605→            float rowH = 22;
606→            float headerH = 18;
607→
608→            // 헤더행
609→            float cx = x;
610→            string[] headers = { "NO", "점검 항목", "점검 기준", "점검 방법", "구분" };
611→            for (int c = 0; c < 5; c++)
612→            {
613→                g.DrawRectangle(penBold, cx, y, colWidths[c], headerH);
614→                g.DrawString(headers[c], fontHeaderBold, brushBlack,
615→                    new RectangleF(cx, y, colWidths[c], headerH), sfCenter);
616→                cx += colWidths[c];
617→            }
618→            for (int d = 1; d <= daysInMonth; d++)
619→            {
620→                g.DrawRectangle(penBlack, cx, y, colWidths[4 + d], headerH);
621→                g.DrawString(d.ToString(), fontHeaderBold, brushBlack,
622→                    new RectangleF(cx, y, colWidths[4 + d], headerH), sfCenter);
623→                cx += colWidths[4 + d];
624→            }
625→            y += headerH;
626→
627→            // 데이터행
628→            for (int r = 0; r < ITEMS.Length; r++)
629→            {
630→                cx = x;
631→
632→                // 고정 컬럼
633→                for (int c = 0; c < 5; c++)
634→                {
635→                    g.DrawRectangle(penBlack, cx, y, colWidths[c], rowH);
636→                    string text = ITEMS[r][c];
637→                    var fmt = (c == 0) ? sfCenter : sfLeft;
638→                    var f = (c <= 1) ? fontCellBold : fontCell;
639→                    g.DrawString(text, f, brushBlack,
640→                        new RectangleF(cx + 2, y, colWidths[c] - 4, rowH), fmt);
641→                    cx += colWidths[c];
642→                }
643→
644→                // 일자 컬럼
645→                for (int d = 1; d <= daysInMonth; d++)
646→                {
647→                    g.DrawRectangle(penBlack, cx, y, colWidths[4 + d], rowH);
648→                    string val = dgv.Rows[r].Cells[$"colDay{d}"].Value?.ToString()?.Trim() ?? "";
649→                    if (!string.IsNullOrEmpty(val))
650→                    {
651→                        var brush = val == "O" ? brushGreen : (val == "X" ? brushRed : brushBlack);
652→                        g.DrawString(val, fontCellBold, brush,
653→                            new RectangleF(cx, y, colWidths[4 + d], rowH), sfCenter);
654→                    }
655→                    cx += colWidths[4 + d];
656→                }
657→                y += rowH;
658→            }
659→
660→            // === 서명란 ===
661→            y += 10;
662→            g.DrawString($"생산 관리자 (SIGN): {txtProdSign.Text}", fontHeader, brushBlack, x, y);
663→            g.DrawString($"품질 관리자 (SIGN): {txtQualSign.Text}", fontHeader, brushBlack, x + 250, y);
664→
665→            // 폰트 해제
666→            fontTitle.Dispose();
667→            fontHeader.Dispose();
668→            fontHeaderBold.Dispose();
669→            fontCell.Dispose();
670→            fontCellBold.Dispose();
671→            fontSmall.Dispose();
672→            penBlack.Dispose();
673→            penBold.Dispose();
674→            brushGreen.Dispose();
675→            brushRed.Dispose();
676→
677→            e.HasMorePages = false;
678→        }
