        /// <summary>
        /// 체크 변경 시 타임스탬프 로그 기록
        /// </summary>
        private void LogCheckAction(int itemNo, string itemName, int day, string oldVal, string newVal)
        {
            try
            {
                string logPath = GetLogFilePath();
                string timestamp = DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss");
                string oldDisplay = string.IsNullOrEmpty(oldVal) ? "-" : oldVal;
                string newDisplay = string.IsNullOrEmpty(newVal) ? "-" : newVal;
                string logLine = $"[{timestamp}] 항목 {itemNo} ({itemName}) | {day}일 | {oldDisplay} → {newDisplay}";

                File.AppendAllText(logPath, logLine + Environment.NewLine, System.Text.Encoding.UTF8);
            }
            catch { }
        }

