            this.Font = new System.Drawing.Font("맑은 고딕", 9F);

            // 컨트롤 추가 순서 (Dock 역순)
            this.Controls.Add(this.dgv);
            this.Controls.Add(this.panelPhoto);
            this.Controls.Add(this.panelBottom);
            this.Controls.Add(this.panelHeader);

            this.panelHeader.ResumeLayout(false);
            this.panelHeaderRow1.ResumeLayout(false);
            this.panelHeaderRow2.ResumeLayout(false);
            this.panelBottom.ResumeLayout(false);
            this.panelPhoto.ResumeLayout(false);
            ((System.ComponentModel.ISupportInitialize)(this.dgv)).EndInit();
            ((System.ComponentModel.ISupportInitialize)(this.pictureBox)).EndInit();
            this.ResumeLayout(false);
        }

        #endregion

        private System.Windows.Forms.Panel panelHeader;
        private System.Windows.Forms.Panel panelHeaderRow1;
        private System.Windows.Forms.Panel panelHeaderRow2;
        private System.Windows.Forms.Panel panelBottom;
        private System.Windows.Forms.Panel panelPhoto;
        private System.Windows.Forms.DataGridView dgv;
        private System.Windows.Forms.DateTimePicker dtpMonth;
        private System.Windows.Forms.PictureBox pictureBox;
        private System.Windows.Forms.Label lblTitle;
        private System.Windows.Forms.Label lblCheckMethod;
        private System.Windows.Forms.Label lblDept;
        private System.Windows.Forms.TextBox txtDept;
        private System.Windows.Forms.Label lblSupervisor;
        private System.Windows.Forms.TextBox txtSupervisor;
        private System.Windows.Forms.Label lblEquipName;
        private System.Windows.Forms.TextBox txtEquipName;
        private System.Windows.Forms.Label lblQuality;
        private System.Windows.Forms.TextBox txtQuality;
        private System.Windows.Forms.Label lblEquipNo;
        private System.Windows.Forms.TextBox txtEquipNo;
        private System.Windows.Forms.Label lblWriter;
        private System.Windows.Forms.TextBox txtWriter;
        private System.Windows.Forms.Label lblReviewer;
        private System.Windows.Forms.TextBox txtReviewer;
        private System.Windows.Forms.Label lblApprover;
        private System.Windows.Forms.TextBox txtApprover;
        private System.Windows.Forms.Label lblProdSign;
        private System.Windows.Forms.TextBox txtProdSign;
