using System;
using System.Collections.Generic;
using System.Drawing;
using System.Drawing.Printing;
using System.IO;
using System.Linq;
using System.Windows.Forms;

namespace WeldMonitor3
{
    public partial class _FrmDailyCheck : Form
    {
        [System.Runtime.InteropServices.DllImport("Gdi32.dll", EntryPoint = "CreateRoundRectRgn")]
        private static extern IntPtr CreateRoundRectRgn(
            int nLeftRect, int nTopRect, int nRightRect, int nBottomRect,
            int nWidthEllipse, int nHeightEllipse);

        // 기본 점검항목 (items.ini 없을 때 사용)
        // [0]=점검항목, [1]=점검기준, [2]=점검방법, [3]=구분
        private static readonly string[][] DEFAULT_ITEMS = new string[][]
        {
            new[] { "AIR 압력및 누기 상태",       "4~6 Kgf, 누기없을것",              "확인",       "1일/SHIFT" },
            new[] { "본체전면부 상태",             "유동 없을 것",                     "확인/눈",    "✓" },
            new[] { "클램프/실린더 작동 상태",     "이상 없을 것",                     "확인",       "✓" },
            new[] { "스패터 방지재개 상태",        "스패터 많아지면 교체",             "확인",       "✓" },
            new[] { "F/PROOF 센서 기능 상태",      "누적·판독 불량 없을것",            "오차확인",   "✓" },
            new[] { "지그 청결 상태",              "청결할 것 24시간/1일",             "확인",       "✓" },
            new[] { "와이어 공급 상태",            "0~11mm",                           "확인",       "✓" },
            new[] { "케이블 상태",                 "접촉불량·꺾임 없을것",             "확인",       "✓" },
            new[] { "배기 덕트 상태",              "흡입기능 정상 작동",               "확인",       "✓" },
            new[] { "용접전류",                    "125~185 A",                        "전류계",     "✓" },
            new[] { "전압",                        "17~23 V",                          "전압계",     "✓" },
            new[] { "GAS 유량",                    "16~20 L/min",                      "유량계",     "✓" },
            new[] { "WIRE 전진속도 조정상태",      "(토/25일)",                        "확인",       "✓" },
            new[] { "드레싱 상태",                 "1일/25일",                         "확인/테스터", "✓" },
            new[] { "팁 교환 상태",                "0.7->1.2mm / 0.9->1.5mm",         "확인",       "✓" },
        };

        // 동적 점검항목 리스트 (파일에서 로드/저장)
        private List<string[]> _items = new List<string[]>();

        private string _basePath;     // DailyCheck 폴더 경로
        private string _photoPath;    // 참조사진 폴더 경로
        private DateTime _currentMonth;
        private bool _loading = false; // 데이터 로드 중 이벤트 방지

        public _FrmDailyCheck()
        {
            InitializeComponent();
            ThemeManager.ApplyDarkTheme(this);
            StyleControls();

            _basePath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "DailyCheck");
            _photoPath = Path.Combine(_basePath, "Photos");

            if (!Directory.Exists(_photoPath))
                Directory.CreateDirectory(_photoPath);

            _currentMonth = new DateTime(DateTime.Now.Year, DateTime.Now.Month, 1);
            dtpMonth.Value = _currentMonth;

            // 점검항목 로드
            LoadItems();

            // 이벤트 연결
            dtpMonth.ValueChanged += DtpMonth_ValueChanged;
            dgv.CellClick += Dgv_CellClick;
            dgv.CellEndEdit += Dgv_CellEndEdit;
            dgv.SelectionChanged += Dgv_SelectionChanged;
            btnSave.Click += BtnSave_Click;
            btnPdf.Click += BtnPdf_Click;
            btnPhotoFolder.Click += BtnPhotoFolder_Click;
            btnAddItem.Click += BtnAddItem_Click;
            btnDeleteItem.Click += BtnDeleteItem_Click;
            btnClose.Click += (s, e) => this.Close();

            // 헤더 텍스트 변경 시 자동 저장
            foreach (var txt in new[] { txtDept, txtSupervisor, txtEquipName, txtQuality,
                                        txtEquipNo, txtWriter, txtReviewer, txtApprover,
                                        txtProdSign, txtQualSign })
            {
                txt.Leave += (s, e) => SaveData();
            }

            SetupGrid();
            LoadData();
        }

        /// <summary>
        /// 다크테마 버튼 스타일 적용
        /// </summary>
        private void StyleControls()
        {
            foreach (Control c in panelBottom.Controls)
            {
                if (c is Button btn)
                {
                    btn.FlatAppearance.BorderColor = ThemeManager.DarkTheme.BorderColor;
                    btn.FlatAppearance.BorderSize = 1;
                    btn.Region = Region.FromHrgn(CreateRoundRectRgn(0, 0, btn.Width, btn.Height, 10, 10));
                    btn.MouseEnter += (s, e) => ((Button)s).BackColor = pColor.Theme.buttonHover;
                    btn.MouseLeave += (s, e) => ((Button)s).BackColor = ThemeManager.DarkTheme.BackgroundLight;
                }
            }
            btnPhotoFolder.FlatAppearance.BorderColor = ThemeManager.DarkTheme.BorderColor;
        }

        #region 점검항목 관리 (파일 기반)

        /// <summary>
        /// 항목 설정 파일 경로 (전체 공용, 월별 X)
        /// </summary>
        private string GetItemsFilePath() => Path.Combine(_basePath, "items.ini");

        /// <summary>
        /// 점검항목 파일에서 로드 (없으면 기본값 사용)
        /// </summary>
        private void LoadItems()
        {
            _items.Clear();
            string filePath = GetItemsFilePath();

            if (File.Exists(filePath))
            {
                try
                {
                    foreach (var line in File.ReadAllLines(filePath, System.Text.Encoding.UTF8))
                    {
                        string trimmed = line.Trim();
                        if (string.IsNullOrEmpty(trimmed) || trimmed.StartsWith("#")) continue;

                        // 탭 구분: 점검항목\t점검기준\t점검방법\t구분
                        string[] parts = trimmed.Split('\t');
                        if (parts.Length >= 4)
                        {
                            _items.Add(new[] { parts[0], parts[1], parts[2], parts[3] });
                        }
                    }
                }
                catch (Exception ex)
                {
                    Logger.Error($"[일상점검] 항목 로드 실패: {ex.Message}");
                }
            }

            // 파일 없거나 비어있으면 기본값
            if (_items.Count == 0)
            {
                foreach (var item in DEFAULT_ITEMS)
                    _items.Add((string[])item.Clone());
                SaveItems();
            }
        }

        /// <summary>
        /// 점검항목 파일에 저장
        /// </summary>
        private void SaveItems()
        {
            try
            {
                if (!Directory.Exists(_basePath))
                    Directory.CreateDirectory(_basePath);

                string filePath = GetItemsFilePath();
                using (var sw = new StreamWriter(filePath, false, System.Text.Encoding.UTF8))
                {
                    sw.WriteLine("# 점검항목 설정 (탭 구분: 점검항목\\t점검기준\\t점검방법\\t구분)");
                    sw.WriteLine("# 이 파일을 직접 수정하거나 프로그램에서 추가/삭제/편집 가능");
                    foreach (var item in _items)
                    {
                        sw.WriteLine($"{item[0]}\t{item[1]}\t{item[2]}\t{item[3]}");
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.Error($"[일상점검] 항목 저장 실패: {ex.Message}");
            }
        }

        /// <summary>
        /// 그리드에서 현재 항목 정보를 _items에 동기화
        /// </summary>
        private void SyncItemsFromGrid()
        {
            _items.Clear();
            for (int i = 0; i < dgv.Rows.Count; i++)
            {
                var row = dgv.Rows[i];
                string item = row.Cells["colItem"].Value?.ToString() ?? "";
                string standard = row.Cells["colStandard"].Value?.ToString() ?? "";
                string method = row.Cells["colMethod"].Value?.ToString() ?? "";
                string type = row.Cells["colType"].Value?.ToString() ?? "";
                _items.Add(new[] { item, standard, method, type });
            }
        }

        /// <summary>
        /// 항목 추가
        /// </summary>
        private void BtnAddItem_Click(object sender, EventArgs e)
        {
            _loading = true;

            int newNo = dgv.Rows.Count + 1;
            int rowIdx = dgv.Rows.Add();
            var row = dgv.Rows[rowIdx];
            row.Cells["colNo"].Value = newNo.ToString();
            row.Cells["colItem"].Value = "(새 항목)";
            row.Cells["colStandard"].Value = "";
            row.Cells["colMethod"].Value = "확인";
            row.Cells["colType"].Value = "✓";

            row.Cells["colItem"].Style.Alignment = DataGridViewContentAlignment.MiddleLeft;
            row.Cells["colStandard"].Style.Alignment = DataGridViewContentAlignment.MiddleLeft;

            // 해당 월 일수 초과 셀 비활성 색상
            int daysInMonth = DateTime.DaysInMonth(_currentMonth.Year, _currentMonth.Month);
            for (int d = daysInMonth + 1; d <= 31; d++)
            {
                row.Cells[$"colDay{d}"].Style.BackColor = Color.FromArgb(50, 50, 50);
            }

            _loading = false;

            // 동기화 + 저장
            SyncItemsFromGrid();
            SaveItems();
            SaveData();

            // 새 항목 셀 편집 모드 진입
            dgv.CurrentCell = dgv.Rows[rowIdx].Cells["colItem"];
            dgv.BeginEdit(true);

            LogCheckAction(newNo, "항목 추가", 0, "", "(새 항목)");
        }

        /// <summary>
        /// 선택된 항목 삭제
        /// </summary>
        private void BtnDeleteItem_Click(object sender, EventArgs e)
        {
            if (dgv.CurrentRow == null) return;
            int rowIdx = dgv.CurrentRow.Index;
            if (rowIdx < 0 || rowIdx >= dgv.Rows.Count) return;

            string itemName = dgv.Rows[rowIdx].Cells["colItem"].Value?.ToString() ?? "";
            var result = MessageBox.Show(
                $"항목 {rowIdx + 1} ({itemName})을(를) 삭제하시겠습니까?\n\n※ 해당 항목의 모든 월별 체크 데이터도 영향을 받습니다.",
                "항목 삭제 확인", MessageBoxButtons.YesNo, MessageBoxIcon.Warning);

            if (result != DialogResult.Yes) return;

            _loading = true;
            dgv.Rows.RemoveAt(rowIdx);

            // NO 컬럼 재번호
            for (int i = 0; i < dgv.Rows.Count; i++)
            {
                dgv.Rows[i].Cells["colNo"].Value = (i + 1).ToString();
            }
            _loading = false;

            // 동기화 + 저장
            SyncItemsFromGrid();
            SaveItems();
            SaveData();

            LogCheckAction(rowIdx + 1, itemName, 0, itemName, "삭제됨");
        }

        #endregion

        #region Grid 설정

        /// <summary>
        /// DataGridView 컬럼/행 초기 설정
        /// </summary>
        private void SetupGrid()
        {
            _loading = true;
            dgv.Columns.Clear();
            dgv.Rows.Clear();

            // NO 컬럼 (읽기 전용)
            AddColumn("colNo", "NO", 30, true);

            // 편집 가능 컬럼
            AddColumn("colItem", "점검 항목", 160, false);
            AddColumn("colStandard", "점검 기준", 160, false);
            AddColumn("colMethod", "점검 방법", 65, false);
            AddColumn("colType", "구분", 65, false);

            // 일자 컬럼 (1~31) — CellClick으로 O/X 토글
            int daysInMonth = DateTime.DaysInMonth(_currentMonth.Year, _currentMonth.Month);
            for (int d = 1; d <= 31; d++)
            {
                var col = new DataGridViewTextBoxColumn();
                col.Name = $"colDay{d}";
                col.HeaderText = d.ToString();
                col.Width = 30;
                col.ReadOnly = true; // CellClick으로 제어
                col.SortMode = DataGridViewColumnSortMode.NotSortable;
                col.DefaultCellStyle.Font = new Font("맑은 고딕", 9F, FontStyle.Bold);

                if (d > daysInMonth)
                {
                    col.DefaultCellStyle.BackColor = Color.FromArgb(50, 50, 50);
                }
                dgv.Columns.Add(col);
            }

            // 항목 행 추가
            for (int i = 0; i < _items.Count; i++)
            {
                int rowIdx = dgv.Rows.Add();
                var row = dgv.Rows[rowIdx];
                row.Cells["colNo"].Value = (i + 1).ToString();
                row.Cells["colItem"].Value = _items[i][0];
                row.Cells["colStandard"].Value = _items[i][1];
                row.Cells["colMethod"].Value = _items[i][2];
                row.Cells["colType"].Value = _items[i][3];

                // 편집 가능 컬럼 왼쪽 정렬
                row.Cells["colItem"].Style.Alignment = DataGridViewContentAlignment.MiddleLeft;
                row.Cells["colStandard"].Style.Alignment = DataGridViewContentAlignment.MiddleLeft;
            }

            // 고정 컬럼 freeze (스크롤해도 왼쪽 고정)
            dgv.Columns["colType"].Frozen = true;

            _loading = false;
        }

        private void AddColumn(string name, string header, int width, bool readOnly)
        {
            var col = new DataGridViewTextBoxColumn();
            col.Name = name;
            col.HeaderText = header;
            col.Width = width;
            col.ReadOnly = readOnly;
            col.SortMode = DataGridViewColumnSortMode.NotSortable;
            dgv.Columns.Add(col);
        }

        #endregion

        #region 셀 편집 완료 → 항목 저장

        /// <summary>
        /// 점검항목/기준/방법/구분 편집 완료 시 항목 파일 저장
        /// </summary>
        private void Dgv_CellEndEdit(object sender, DataGridViewCellEventArgs e)
        {
            if (_loading || e.RowIndex < 0) return;

            // 편집 가능 컬럼 (colItem=1, colStandard=2, colMethod=3, colType=4)
            if (e.ColumnIndex >= 1 && e.ColumnIndex <= 4)
            {
                SyncItemsFromGrid();
                SaveItems();
                SaveData();
            }
        }

        #endregion

        #region 셀 클릭 → O/X 토글 + 로그

        private void Dgv_CellClick(object sender, DataGridViewCellEventArgs e)
        {
            if (_loading || e.RowIndex < 0 || e.ColumnIndex < 5) return;

            int day = e.ColumnIndex - 4; // colDay1 = index 5
            if (day < 1 || day > 31) return;

            int daysInMonth = DateTime.DaysInMonth(_currentMonth.Year, _currentMonth.Month);
            if (day > daysInMonth) return;

            var cell = dgv.Rows[e.RowIndex].Cells[e.ColumnIndex];
            string current = cell.Value?.ToString()?.Trim() ?? "";

            // 순환: "" → O → X → ""
            string next;
            if (current == "") next = "O";
            else if (current == "O") next = "X";
            else next = "";

            cell.Value = next;
            ApplyCellColor(cell, next);

            // 체크 로그 기록
            string itemName = dgv.Rows[e.RowIndex].Cells["colItem"].Value?.ToString() ?? "";
            LogCheckAction(e.RowIndex + 1, itemName, day, current, next);

            // 자동 저장
            SaveData();
        }

        /// <summary>
        /// O/X 값에 따른 셀 색상 적용
        /// </summary>
        private void ApplyCellColor(DataGridViewCell cell, string value)
        {
            if (value == "O")
            {
                cell.Style.ForeColor = Color.LimeGreen;
                cell.Style.BackColor = Color.FromArgb(30, 60, 30);
            }
            else if (value == "X")
            {
                cell.Style.ForeColor = Color.Red;
                cell.Style.BackColor = Color.FromArgb(70, 25, 25);
            }
            else
            {
                cell.Style.ForeColor = ThemeManager.DarkTheme.TextPrimary;
                cell.Style.BackColor = ThemeManager.DarkTheme.BackgroundMedium;
            }
        }

        #endregion

        #region 참조사진

        private void Dgv_SelectionChanged(object sender, EventArgs e)
        {
            if (dgv.CurrentRow == null) return;
            int rowIdx = dgv.CurrentRow.Index;
            if (rowIdx < 0 || rowIdx >= dgv.Rows.Count) return;

            LoadPhoto(rowIdx);
        }

        /// <summary>
        /// 선택된 항목의 참조사진 로드
        /// </summary>
        private void LoadPhoto(int itemIndex)
        {
            // 파일명: 01.jpg, 01.png 등
            string prefix = (itemIndex + 1).ToString("D2");
            string itemName = "";
            if (itemIndex < dgv.Rows.Count)
                itemName = dgv.Rows[itemIndex].Cells["colItem"].Value?.ToString() ?? "";
            lblPhotoTitle.Text = $"{itemIndex + 1}. {itemName}";

            // 확장자 순회
            string[] exts = { ".jpg", ".jpeg", ".png", ".bmp", ".gif" };
            foreach (var ext in exts)
            {
                string path = Path.Combine(_photoPath, prefix + ext);
                if (File.Exists(path))
                {
                    try
                    {
                        // 파일 잠금 방지
                        using (var fs = new FileStream(path, FileMode.Open, FileAccess.Read))
                        {
                            pictureBox.Image?.Dispose();
                            pictureBox.Image = Image.FromStream(fs);
                        }
                        return;
                    }
                    catch { }
                }
            }

            // 사진 없음
            pictureBox.Image?.Dispose();
            pictureBox.Image = null;
        }

        private void BtnPhotoFolder_Click(object sender, EventArgs e)
        {
            if (!Directory.Exists(_photoPath))
                Directory.CreateDirectory(_photoPath);

            System.Diagnostics.Process.Start("explorer.exe", _photoPath);
        }

        #endregion

        #region 월 변경

        private void DtpMonth_ValueChanged(object sender, EventArgs e)
        {
            var newMonth = new DateTime(dtpMonth.Value.Year, dtpMonth.Value.Month, 1);
            if (newMonth == _currentMonth) return;

            _currentMonth = newMonth;
            SetupGrid();
            LoadData();
        }

        #endregion

        #region 데이터 저장/로드

        /// <summary>
        /// 월별 데이터 폴더 경로
        /// </summary>
        private string GetMonthFolder()
        {
            string folder = Path.Combine(_basePath, _currentMonth.ToString("yyyy_MM"));
            if (!Directory.Exists(folder))
                Directory.CreateDirectory(folder);
            return folder;
        }

        private string GetDataFilePath() => Path.Combine(GetMonthFolder(), "check_data.ini");
        private string GetLogFilePath() => Path.Combine(GetMonthFolder(), "check_log.txt");

        private void BtnSave_Click(object sender, EventArgs e)
        {
            SyncItemsFromGrid();
            SaveItems();
            SaveData();
            MessageBox.Show("저장 완료", "알림", MessageBoxButtons.OK, MessageBoxIcon.Information);
        }

        /// <summary>
        /// 체크 데이터 저장 (INI 형식)
        /// </summary>
        private void SaveData()
        {
            if (_loading) return;

            try
            {
                string filePath = GetDataFilePath();
                using (var sw = new StreamWriter(filePath, false, System.Text.Encoding.UTF8))
                {
                    // 헤더 정보
                    sw.WriteLine("[Header]");
                    sw.WriteLine($"Dept={txtDept.Text}");
                    sw.WriteLine($"Supervisor={txtSupervisor.Text}");
                    sw.WriteLine($"EquipName={txtEquipName.Text}");
                    sw.WriteLine($"Quality={txtQuality.Text}");
                    sw.WriteLine($"EquipNo={txtEquipNo.Text}");
                    sw.WriteLine($"Writer={txtWriter.Text}");
                    sw.WriteLine($"Reviewer={txtReviewer.Text}");
                    sw.WriteLine($"Approver={txtApprover.Text}");
                    sw.WriteLine($"ProdSign={txtProdSign.Text}");
                    sw.WriteLine($"QualSign={txtQualSign.Text}");
                    sw.WriteLine();

                    // 각 항목별 일자 데이터
                    for (int i = 0; i < dgv.Rows.Count; i++)
                    {
                        sw.WriteLine($"[Item{i + 1}]");
                        for (int d = 1; d <= 31; d++)
                        {
                            string val = dgv.Rows[i].Cells[$"colDay{d}"].Value?.ToString()?.Trim() ?? "";
                            if (!string.IsNullOrEmpty(val))
                                sw.WriteLine($"Day{d}={val}");
                        }
                        sw.WriteLine();
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.Error($"[일상점검] 저장 실패: {ex.Message}");
            }
        }

        /// <summary>
        /// 체크 데이터 로드
        /// </summary>
        private void LoadData()
        {
            _loading = true;
            string filePath = GetDataFilePath();

            if (!File.Exists(filePath))
            {
                // 기본값
                txtDept.Text = "생기/공무팀";
                txtSupervisor.Text = "설비관리담당자";
                txtEquipName.Text = "";
                txtQuality.Text = "19기";
                txtEquipNo.Text = "IM-000-RW-01-32";
                _loading = false;
                return;
            }

            try
            {
                string currentSection = "";
                foreach (var line in File.ReadAllLines(filePath, System.Text.Encoding.UTF8))
                {
                    string trimmed = line.Trim();
                    if (string.IsNullOrEmpty(trimmed)) continue;

                    if (trimmed.StartsWith("[") && trimmed.EndsWith("]"))
                    {
                        currentSection = trimmed.Substring(1, trimmed.Length - 2);
                        continue;
                    }

                    int eqIdx = trimmed.IndexOf('=');
                    if (eqIdx < 0) continue;
                    string key = trimmed.Substring(0, eqIdx);
                    string val = trimmed.Substring(eqIdx + 1);

                    if (currentSection == "Header")
                    {
                        switch (key)
                        {
                            case "Dept": txtDept.Text = val; break;
                            case "Supervisor": txtSupervisor.Text = val; break;
                            case "EquipName": txtEquipName.Text = val; break;
                            case "Quality": txtQuality.Text = val; break;
                            case "EquipNo": txtEquipNo.Text = val; break;
                            case "Writer": txtWriter.Text = val; break;
                            case "Reviewer": txtReviewer.Text = val; break;
                            case "Approver": txtApprover.Text = val; break;
                            case "ProdSign": txtProdSign.Text = val; break;
                            case "QualSign": txtQualSign.Text = val; break;
                        }
                    }
                    else if (currentSection.StartsWith("Item"))
                    {
                        int itemNo;
                        if (!int.TryParse(currentSection.Substring(4), out itemNo)) continue;
                        if (itemNo < 1 || itemNo > dgv.Rows.Count) continue;

                        if (key.StartsWith("Day"))
                        {
                            int dayNo;
                            if (!int.TryParse(key.Substring(3), out dayNo)) continue;
                            if (dayNo < 1 || dayNo > 31) continue;

                            string colName = $"colDay{dayNo}";
                            var cell = dgv.Rows[itemNo - 1].Cells[colName];
                            cell.Value = val;
                            ApplyCellColor(cell, val);
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.Error($"[일상점검] 로드 실패: {ex.Message}");
            }

            _loading = false;
        }

        #endregion

        #region 체크 로그 기록

        /// <summary>
        /// 체크 변경 시 타임스탬프 로그 기록
        /// </summary>
        private void LogCheckAction(int itemNo, string itemName, int day, string oldVal, string newVal)
        {
            try
            {
                string logPath = GetLogFilePath();
                string timestamp = DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss");
                string oldDisplay = string.IsNullOrEmpty(oldVal) ? "-" : oldVal;
                string newDisplay = string.IsNullOrEmpty(newVal) ? "-" : newVal;

                string logLine;
                if (day == 0)
                {
                    // 항목 추가/삭제 로그
                    logLine = $"[{timestamp}] 항목 {itemNo} ({itemName}) | {newDisplay}";
                }
                else
                {
                    logLine = $"[{timestamp}] 항목 {itemNo} ({itemName}) | {day}일 | {oldDisplay} → {newDisplay}";
                }

                File.AppendAllText(logPath, logLine + Environment.NewLine, System.Text.Encoding.UTF8);
            }
            catch { }
        }

        #endregion

        #region PDF 출력

        private void BtnPdf_Click(object sender, EventArgs e)
        {
            using (var sfd = new SaveFileDialog())
            {
                sfd.Filter = "PDF 파일|*.pdf";
                sfd.FileName = $"점검체크시트_{_currentMonth:yyyy_MM}.pdf";

                if (sfd.ShowDialog() != DialogResult.OK) return;

                try
                {
                    using (var pd = new PrintDocument())
                    {
                        pd.PrintPage += PrintCheckSheet;
                        pd.DefaultPageSettings.Landscape = true;
                        pd.DefaultPageSettings.Margins = new Margins(30, 30, 30, 30);

                        // Microsoft Print to PDF 확인
                        bool pdfPrinterFound = false;
                        foreach (string printer in PrinterSettings.InstalledPrinters)
                        {
                            if (printer.Contains("Microsoft Print to PDF"))
                            {
                                pd.PrinterSettings.PrinterName = printer;
                                pdfPrinterFound = true;
                                break;
                            }
                        }

                        if (!pdfPrinterFound)
                        {
                            MessageBox.Show("'Microsoft Print to PDF' 프린터를 찾을 수 없습니다.\n인쇄 대화상자에서 PDF 프린터를 선택해주세요.",
                                "알림", MessageBoxButtons.OK, MessageBoxIcon.Warning);

                            using (var printDlg = new PrintDialog())
                            {
                                printDlg.Document = pd;
                                if (printDlg.ShowDialog() != DialogResult.OK) return;
                            }
                            pd.Print();
                        }
                        else
                        {
                            pd.PrinterSettings.PrintToFile = true;
                            pd.PrinterSettings.PrintFileName = sfd.FileName;
                            pd.Print();
                        }
                    }

                    // PDF 생성 후 열기
                    if (File.Exists(sfd.FileName))
                    {
                        System.Diagnostics.Process.Start(sfd.FileName);
                        LogCheckAction(0, "PDF 출력", 0, "", sfd.FileName);
                    }
                }
                catch (Exception ex)
                {
                    MessageBox.Show($"PDF 생성 실패: {ex.Message}", "오류",
                        MessageBoxButtons.OK, MessageBoxIcon.Error);
                }
            }
        }

        /// <summary>
        /// 체크시트 인쇄 렌더링 (Landscape A4)
        /// </summary>
        private void PrintCheckSheet(object sender, PrintPageEventArgs e)
        {
            Graphics g = e.Graphics;
            var area = e.MarginBounds;
            float x = area.Left;
            float y = area.Top;
            float pageW = area.Width;

            int rowCount = dgv.Rows.Count;

            // 폰트
            var fontTitle = new Font("맑은 고딕", 14, FontStyle.Bold);
            var fontHeader = new Font("맑은 고딕", 7);
            var fontHeaderBold = new Font("맑은 고딕", 7, FontStyle.Bold);
            var fontCell = new Font("맑은 고딕", 6.5f);
            var fontCellBold = new Font("맑은 고딕", 7, FontStyle.Bold);

            var penBlack = new Pen(Color.Black, 0.5f);
            var penBold = new Pen(Color.Black, 1.2f);
            var brushBlack = Brushes.Black;
            var brushGreen = new SolidBrush(Color.FromArgb(0, 128, 0));
            var brushRed = new SolidBrush(Color.FromArgb(200, 0, 0));
            var sfCenter = new StringFormat { Alignment = StringAlignment.Center, LineAlignment = StringAlignment.Center };
            var sfLeft = new StringFormat { Alignment = StringAlignment.Near, LineAlignment = StringAlignment.Center };

            // === 제목 ===
            g.DrawString("(설비/용접조건) 점검 체크시트", fontTitle, brushBlack, x + pageW / 2, y, sfCenter);
            y += 28;

            // === 헤더 정보 ===
            string headerLine1 = $"관리부서: {txtDept.Text}    관리감독: {txtSupervisor.Text}    설비명칭: {txtEquipName.Text}    " +
                                 $"점검방법: 점검 항목/점검 기준/점검 방법에 따름";
            string headerLine2 = $"품질: {txtQuality.Text}    설비번호: {txtEquipNo.Text}    " +
                                 $"작성: {txtWriter.Text}    검토: {txtReviewer.Text}    승인: {txtApprover.Text}    " +
                                 $"{_currentMonth:yyyy년 MM월} 일상 점검";
            g.DrawString(headerLine1, fontHeader, brushBlack, x, y);
            y += 14;
            g.DrawString(headerLine2, fontHeader, brushBlack, x, y);
            y += 18;

            // === 테이블 ===
            int daysInMonth = DateTime.DaysInMonth(_currentMonth.Year, _currentMonth.Month);

            // 컬럼 폭 계산
            float[] colWidths = new float[5 + 31];
            colWidths[0] = 22;   // NO
            colWidths[1] = 130;  // 점검항목
            colWidths[2] = 125;  // 점검기준
            colWidths[3] = 45;   // 점검방법
            colWidths[4] = 48;   // 구분
            float fixedW = colWidths[0] + colWidths[1] + colWidths[2] + colWidths[3] + colWidths[4];
            float dayColW = (pageW - fixedW) / daysInMonth;
            for (int d = 0; d < daysInMonth; d++)
                colWidths[5 + d] = dayColW;

            // 행 높이 동적 (항목 많으면 줄임)
            float availableH = area.Bottom - y - 30; // 서명란 여유
            float headerH = 18;
            float rowH = Math.Min(22, (availableH - headerH) / rowCount);
            if (rowH < 12) rowH = 12;

            // 헤더행
            float cx = x;
            string[] headers = { "NO", "점검 항목", "점검 기준", "점검 방법", "구분" };
            for (int c = 0; c < 5; c++)
            {
                g.DrawRectangle(penBold, cx, y, colWidths[c], headerH);
                g.DrawString(headers[c], fontHeaderBold, brushBlack,
                    new RectangleF(cx, y, colWidths[c], headerH), sfCenter);
                cx += colWidths[c];
            }
            for (int d = 1; d <= daysInMonth; d++)
            {
                g.DrawRectangle(penBlack, cx, y, colWidths[4 + d], headerH);
                g.DrawString(d.ToString(), fontHeaderBold, brushBlack,
                    new RectangleF(cx, y, colWidths[4 + d], headerH), sfCenter);
                cx += colWidths[4 + d];
            }
            y += headerH;

            // 데이터행 (그리드에서 직접 읽기)
            for (int r = 0; r < rowCount; r++)
            {
                cx = x;
                var row = dgv.Rows[r];

                // 고정 컬럼 5개: NO, 항목, 기준, 방법, 구분
                string[] cellNames = { "colNo", "colItem", "colStandard", "colMethod", "colType" };
                for (int c = 0; c < 5; c++)
                {
                    g.DrawRectangle(penBlack, cx, y, colWidths[c], rowH);
                    string text = row.Cells[cellNames[c]].Value?.ToString() ?? "";
                    var fmt = (c == 0) ? sfCenter : sfLeft;
                    var f = (c <= 1) ? fontCellBold : fontCell;
                    g.DrawString(text, f, brushBlack,
                        new RectangleF(cx + 2, y, colWidths[c] - 4, rowH), fmt);
                    cx += colWidths[c];
                }

                // 일자 컬럼
                for (int d = 1; d <= daysInMonth; d++)
                {
                    g.DrawRectangle(penBlack, cx, y, colWidths[4 + d], rowH);
                    string val = row.Cells[$"colDay{d}"].Value?.ToString()?.Trim() ?? "";
                    if (!string.IsNullOrEmpty(val))
                    {
                        var brush = val == "O" ? brushGreen : (val == "X" ? brushRed : brushBlack);
                        g.DrawString(val, fontCellBold, brush,
                            new RectangleF(cx, y, colWidths[4 + d], rowH), sfCenter);
                    }
                    cx += colWidths[4 + d];
                }
                y += rowH;
            }

            // === 서명란 ===
            y += 10;
            g.DrawString($"생산 관리자 (SIGN): {txtProdSign.Text}", fontHeader, brushBlack, x, y);
            g.DrawString($"품질 관리자 (SIGN): {txtQualSign.Text}", fontHeader, brushBlack, x + 250, y);

            // 폰트 해제
            fontTitle.Dispose();
            fontHeader.Dispose();
            fontHeaderBold.Dispose();
            fontCell.Dispose();
            fontCellBold.Dispose();
            penBlack.Dispose();
            penBold.Dispose();
            brushGreen.Dispose();
            brushRed.Dispose();

            e.HasMorePages = false;
        }

        #endregion
    }
}

