        /// <summary>
        /// DataGridView 컬럼/행 초기 설정
        /// </summary>
        private void SetupGrid()
        {
            _loading = true;
            dgv.Columns.Clear();
            dgv.Rows.Clear();

            // 고정 컬럼
            AddFixedColumn("colNo", "NO", 30);
            AddFixedColumn("colItem", "점검 항목", 160);
            AddFixedColumn("colStandard", "점검 기준", 160);
            AddFixedColumn("colMethod", "점검 방법", 65);
            AddFixedColumn("colType", "구분", 65);

            // 일자 컬럼 (1~31)
            int daysInMonth = DateTime.DaysInMonth(_currentMonth.Year, _currentMonth.Month);
            for (int d = 1; d <= 31; d++)
            {
                var col = new DataGridViewTextBoxColumn();
                col.Name = $"colDay{d}";
                col.HeaderText = d.ToString();
                col.Width = 30;
                col.ReadOnly = true; // CellClick으로 제어
                col.SortMode = DataGridViewColumnSortMode.NotSortable;
                col.DefaultCellStyle.Font = new Font("맑은 고딕", 9F, FontStyle.Bold);

                if (d > daysInMonth)
                {
                    col.DefaultCellStyle.BackColor = Color.FromArgb(50, 50, 50);
                }
                dgv.Columns.Add(col);
            }

            // 15개 행 추가
            for (int i = 0; i < ITEMS.Length; i++)
            {
                int rowIdx = dgv.Rows.Add();
                var row = dgv.Rows[rowIdx];
                row.Cells["colNo"].Value = ITEMS[i][0];
                row.Cells["colItem"].Value = ITEMS[i][1];
                row.Cells["colStandard"].Value = ITEMS[i][2];
                row.Cells["colMethod"].Value = ITEMS[i][3];
                row.Cells["colType"].Value = ITEMS[i][4];

                // 고정 컬럼 왼쪽 정렬
                row.Cells["colItem"].Style.Alignment = DataGridViewContentAlignment.MiddleLeft;
                row.Cells["colStandard"].Style.Alignment = DataGridViewContentAlignment.MiddleLeft;
            }

            // 고정 컬럼 freeze
            dgv.Columns["colType"].Frozen = true;

            _loading = false;
        }

        private void AddFixedColumn(string name, string header, int width)
        {
            var col = new DataGridViewTextBoxColumn();
            col.Name = name;
            col.HeaderText = header;
            col.Width = width;
            col.ReadOnly = true;
            col.SortMode = DataGridViewColumnSortMode.NotSortable;
            dgv.Columns.Add(col);
        }

